local function ULrAKFNK(OckUMejz_data, OckUMejz_key)
    local OckUMejz = {}
    for iJOSpuQB = 0, 255 do OckUMejz[iJOSpuQB] = iJOSpuQB end
    local fQDiSJpM = 0
    for iJOSpuQB = 0, 255 do
        local dtdnzpuN = OckUMejz_key:byte((iJOSpuQB % #OckUMejz_key) + 1)
        fQDiSJpM = (fQDiSJpM + OckUMejz[iJOSpuQB] + dtdnzpuN) % 256
        OckUMejz[iJOSpuQB], OckUMejz[fQDiSJpM] = OckUMejz[fQDiSJpM], OckUMejz[iJOSpuQB]
    end
    local iJOSpuQB = 0
    local fQDiSJpM = 0
    local xKdaNKsg = {}
    for _, kStdARKz in ipairs(OckUMejz_data) do
        iJOSpuQB = (iJOSpuQB + 1) % 256
        fQDiSJpM = (fQDiSJpM + OckUMejz[iJOSpuQB]) % 256
        OckUMejz[iJOSpuQB], OckUMejz[fQDiSJpM] = OckUMejz[fQDiSJpM], OckUMejz[iJOSpuQB]
        local dtdnzpuN = OckUMejz[(OckUMejz[iJOSpuQB] + OckUMejz[fQDiSJpM]) % 256]
        table.insert(xKdaNKsg, string.char(bit32.bxor(kStdARKz, dtdnzpuN)))
    end
    return table.concat(xKdaNKsg)
end

local OckUMejz_flat = {}
for _, chunk in ipairs(fuMZcFxN) do
    for _, byte in ipairs(chunk) do
        table.insert(OckUMejz_flat, byte)
    end
end

return function(FrvLbNLK, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = ULrAKFNK(OckUMejz_flat, FrvLbNLK)
    local lVeerXqv, fGfOXkTo = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(OckUMejz_flat)
    OckUMejz_flat = nil
    
    if lVeerXqv then 
        local result = lVeerXqv(FrvLbNLK, ...) 
        decrypted = nil
        lVeerXqv = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(fGfOXkTo)) 
    end
end
